function mediaLabel(status, asset) {
  if (status === "text-first") return "Text-first / approved no poster";
  if (!asset) return "Media role open / replace through canonical data";
  return asset.startsWith("http") ? `Remote media reference / ${asset}` : `Local media role / ${asset}`;
}

async function imageBox(parent, name, width, height, media) {
  const asset = media?.src || "";
  const rect = rectangle(parent, name, width, height, {
    fill: PORTFOLIO_MODEL.tokens.fog,
    radius: 20,
    stroke: PORTFOLIO_MODEL.tokens.stage,
    strokeOpacity: 0.18,
  });
  rect.setPluginData("mediaStatus", media?.status || "open-role");
  rect.setPluginData("canonicalSource", asset);
  rect.setPluginData("focalPoint", media?.focalPoint || "50% 50%");
  rect.setPluginData("alt", typeof media?.alt === "string" ? media.alt : JSON.stringify(media?.alt || {}));

  if (!asset) {
    text(parent, `${name} / status`, mediaLabel(media?.status, asset), {
      size: 11,
      color: PORTFOLIO_MODEL.tokens.coral,
      width,
    });
    return rect;
  }

  const assetUrl = asset.startsWith("http") ? asset : `${PORTFOLIO_MODEL.siteUrl}${asset}`;
  try {
    const image = await figma.createImageAsync(assetUrl);
    rect.fills = [{ type: "IMAGE", imageHash: image.hash, scaleMode: "FILL" }];
  } catch (error) {
    const prefix = asset.startsWith("http") ? "Remote media reference" : "Local production media";
    text(parent, `${name} / unresolved source`, `${prefix}: ${asset}`, {
      size: 11,
      color: PORTFOLIO_MODEL.tokens.coral,
      width,
    });
  }
  return rect;
}

