async function createHybridSections(parent, mode) {
  const copy = PORTFOLIO_MODEL.content.en;
  for (const sectionKey of PORTFOLIO_MODEL.sectionOrder) {
    if (sectionKey === "hero") await addHero(parent, mode, copy);
    if (sectionKey === "collaborations") addCollaborations(parent, mode, copy);
    if (sectionKey === "watchLoop") await addWatchLoop(parent, mode, copy);
    if (sectionKey === "availability") addAvailability(parent, mode, copy);
    if (sectionKey === "selectedWorks") await addSelectedWorks(parent, mode, copy);
    if (sectionKey === "collaborationFit") addCollaborationFit(parent, mode, copy);
    if (sectionKey === "archive") addArchive(parent, mode, copy);
    if (sectionKey === "contact") addContact(parent, mode, copy);
  }
}

function createTokenPage() {
  const page = figma.createPage();
  page.name = "02 Design System / Hybrid";
  const board = frame(page, "Editorial Watch Loop Hybrid / Tokens", 820, 720, { fill: PORTFOLIO_MODEL.tokens.paper });
  setAutoLayout(board, "VERTICAL", 18, 42);
  text(board, "Design title", "Editorial Watch Loop Hybrid", { size: 42 });
  for (const [name, value] of Object.entries(PORTFOLIO_MODEL.tokens)) {
    const row = frame(board, `Token / ${name}`, 736, 52, { fill: PORTFOLIO_MODEL.tokens.paper });
    setAutoLayout(row, "HORIZONTAL", 18, 0);
    rectangle(row, `Swatch / ${name}`, 52, 52, { fill: value, radius: 10, stroke: PORTFOLIO_MODEL.tokens.stage, strokeOpacity: 0.18 });
    text(row, `Label / ${name}`, `${name} · ${value}`, { size: 15, fontRole: "sansMedium" });
  }
  text(board, "Sans type", PORTFOLIO_MODEL.typography.sans, { size: 18 });
  text(board, "Editorial type", PORTFOLIO_MODEL.typography.editorial, { size: 18, fontRole: "editorial" });
}

async function createPortfolioPage(mode) {
  const page = figma.createPage();
  const mobile = mode === "mobile";
  page.name = mobile ? "04 Mobile Layouts / Hybrid" : "03 Desktop Layouts / Hybrid";
  const portfolio = frame(page, mobile ? "Mobile / Portfolio / Editorial Watch Loop Hybrid" : "Desktop / Portfolio / Editorial Watch Loop Hybrid", mobile ? 390 : 1440, 10, { fill: PORTFOLIO_MODEL.tokens.paper });
  setAutoLayout(portfolio, "VERTICAL", 0, mobile ? 18 : 64);
  portfolio.layoutSizingVertical = "HUG";
  await createHybridSections(portfolio, mode);
}

async function main() {
  await loadFonts();
  createTokenPage();
  await createPortfolioPage("desktop");
  await createPortfolioPage("mobile");
  const populatedPages = figma.root.children.filter((page) => page.children.length > 0);
  figma.currentPage = populatedPages[0] || figma.currentPage;
  figma.viewport.scrollAndZoomIntoView(figma.currentPage.children);
  figma.closePlugin("Editable editorial watch loop hybrid created from canonical repository data.");
}

main().catch((error) => figma.closePlugin(`Importer failed: ${error.message}`));
